{
  "sentences": [
    {
      "text": "請你走進來。",
      "pinyin": "Qǐng nǐ zǒu jìnlái.",
      "pinyin_numeric": "qing3 ni3 zou3 jin4lai2",
      "translation_en": "Please walk in.",
      "translation_ko": "안으로 걸어 들어오세요."
    },
    {
      "text": "他跑出去了。",
      "pinyin": "Tā pǎo chūqù le.",
      "pinyin_numeric": "ta1 pao3 chu1qu4 le0",
      "translation_en": "He ran out.",
      "translation_ko": "그가 뛰어 나갔어요."
    },
    {
      "text": "貓從窗戶跳進來。",
      "pinyin": "Māo cóng chuānghu tiào jìnlái.",
      "pinyin_numeric": "mao1 cong2 chuang1hu4 tiao4 jin4lai2",
      "translation_en": "The cat jumped in through the window.",
      "translation_ko": "고양이가 창문에서 뛰어 들어왔어요."
    },
    {
      "text": "請把書拿出來。",
      "pinyin": "Qǐng bǎ shū ná chūlái.",
      "pinyin_numeric": "qing3 ba3 shu1 na2 chu1lai2",
      "translation_en": "Please take the book out.",
      "translation_ko": "책을 꺼내 주세요."
    },
    {
      "text": "他把手機放進去了。",
      "pinyin": "Tā bǎ shǒujī fàng jìnqù le.",
      "pinyin_numeric": "ta1 ba3 shou3ji1 fang4 jin4qu4 le0",
      "translation_en": "He put the phone in.",
      "translation_ko": "그가 핸드폰을 안에 넣었어요."
    },
    {
      "text": "我們帶咖啡進去。",
      "pinyin": "Wǒmen dài kāfēi jìnqù.",
      "pinyin_numeric": "wo3men0 dai4 ka1fei1 jin4qu4",
      "translation_en": "We bring coffee in.",
      "translation_ko": "우리는 커피를 가지고 들어가요."
    },
    {
      "text": "她從教室走出來。",
      "pinyin": "Tā cóng jiàoshì zǒu chūlái.",
      "pinyin_numeric": "ta1 cong2 jiao4shi4 zou3 chu1lai2",
      "translation_en": "She walked out of the classroom.",
      "translation_ko": "그녀가 교실에서 걸어 나왔어요."
    },
    {
      "text": "請把垃圾拿出去。",
      "pinyin": "Qǐng bǎ lèsè ná chūqù.",
      "pinyin_numeric": "qing3 ba3 le4se4 na2 chu1qu4",
      "translation_en": "Please take the trash out.",
      "translation_ko": "쓰레기를 밖으로 가져가 주세요."
    },
    {
      "text": "他騎腳踏車進來了。",
      "pinyin": "Tā qí jiǎotàchē jìnlái le.",
      "pinyin_numeric": "ta1 qi2 jiao3ta4che1 jin4lai2 le0",
      "translation_en": "He rode his bike in.",
      "translation_ko": "그가 자전거를 타고 들어왔어요."
    },
    {
      "text": "鳥從窗戶飛出去了。",
      "pinyin": "Niǎo cóng chuānghu fēi chūqù le.",
      "pinyin_numeric": "niao3 cong2 chuang1hu4 fei1 chu1qu4 le0",
      "translation_en": "The bird flew out of the window.",
      "translation_ko": "새가 창문에서 날아 나갔어요."
    }
  ]
}
